parameters.old_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications via email.
 * Currently email is the only channel; the model is designed to
 * accommodate additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily_digest: batched and sent once per day
 * - weekly_digest: batched and sent once per week
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Per-user notification preferences stored in the database.
 */
export interface UserPreferences {
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Master switch — when false, no email notifications are sent. */
  emailEnabled: boolean;
  /** Delivery cadence for email notifications. */
  emailFrequency: EmailFrequency;
  /** Notification categories the user is subscribed to. */
  subscribedCategories: NotificationType[];
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId is set separately).
 */
export interface CreateUserPreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating existing user preferences.
 */
export interface UpdateUserPreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification categories a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default preferences applied when a new user is created.
 */
export const DEFAULT_PREFERENCES: Omit<UserPreferences, 'id' | 'userId' | 'createdAt' | 'updatedAt'> = {
  emailEnabled: true,
  emailFrequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple
 * channels (email, SMS, webhook). Per-channel settings allow users to
 * independently enable/disable each channel and subscribe to specific
 * notification categories per channel.
 *
 * Backward compatibility: The legacy emailEnabled, emailFrequency, and
 * subscribedCategories fields are kept in sync with channels.email.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * How often email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily_digest: batched and sent once per day
 * - weekly_digest: batched and sent once per week
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Per-channel notification preferences.
 */
export interface ChannelPreferences {
  /** Whether this channel is enabled for the user. */
  enabled: boolean;
  /** Notification categories the user is subscribed to on this channel. */
  subscribedCategories: NotificationType[];
}

/**
 * Map of channel-specific preferences.
 */
export type ChannelPreferencesMap = Partial<Record<NotificationChannel, ChannelPreferences>>;

/**
 * Per-user notification preferences stored in the database.
 */
export interface UserPreferences {
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Master switch for email — kept for backward compatibility with channels.email. */
  emailEnabled: boolean;
  /** Delivery cadence for email notifications. */
  emailFrequency: EmailFrequency;
  /** Email subscribed categories — kept for backward compatibility with channels.email. */
  subscribedCategories: NotificationType[];
  /** Per-channel notification preferences. */
  channels: ChannelPreferencesMap;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId is set separately).
 */
export interface CreateUserPreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
  /** Per-channel overrides. If provided, these take precedence for non-email channels. */
  channels?: Partial<Record<NotificationChannel, Partial<ChannelPreferences>>>;
}

/**
 * Input for updating existing user preferences.
 */
export interface UpdateUserPreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
  /** Per-channel updates. Merges with existing channel preferences. */
  channels?: Partial<Record<NotificationChannel, Partial<ChannelPreferences>>>;
}

/**
 * All notification categories a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default per-channel preferences.
 * Email: enabled by default (opt-in). SMS/webhook: disabled by default (opt-out).
 */
export const DEFAULT_CHANNEL_PREFERENCES: Record<'email' | 'sms' | 'webhook', ChannelPreferences> = {
  email: {
    enabled: true,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  },
  sms: {
    enabled: false,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  },
  webhook: {
    enabled: false,
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  },
};

/**
 * Default preferences applied when a new user is created.
 */
export const DEFAULT_PREFERENCES: Omit<UserPreferences, 'id' | 'userId' | 'createdAt' | 'updatedAt'> = {
  emailEnabled: true,
  emailFrequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  channels: {
    email: { ...DEFAULT_CHANNEL_PREFERENCES.email, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    sms: { ...DEFAULT_CHANNEL_PREFERENCES.sms, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    webhook: { ...DEFAULT_CHANNEL_PREFERENCES.webhook, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
  },
};

parameters.content:
/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification preferences and
 * query methods used by NotificationService to check whether a
 * notification should be delivered on a given channel.
 *
 * Supports per-channel preferences (email, SMS, webhook) while
 * maintaining backward compatibility with the email-only API.
 *
 * Depends on:
 * - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  ChannelPreferences,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { ALL_NOTIFICATION_CATEGORIES, DEFAULT_PREFERENCES, DEFAULT_CHANNEL_PREFERENCES } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getByUserId(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreateForUser(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createForUser(userId);
  }

  /**
   * Create default preferences for a user.
   */
  createForUser(userId: string, input?: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${userId}`);
    }

    const emailEnabled = input?.emailEnabled ?? DEFAULT_PREFERENCES.emailEnabled;
    const subscribedCategories = input?.subscribedCategories ?? [...DEFAULT_PREFERENCES.subscribedCategories];

    // Build channels map — start from defaults, apply email legacy fields, then channel overrides
    const channels = buildChannelsFromInput(emailEnabled, subscribedCategories, input?.channels);

    const now = new Date();
    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      emailEnabled,
      emailFrequency: input?.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency,
      subscribedCategories,
      channels,
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(prefs);
    this.logger.info(`Created preferences for user: ${userId}`);
    return prefs;
  }

  /**
   * Update a user's notification preferences.
   */
  updateForUser(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updates: Partial<UserPreferences> = { updatedAt: new Date() };

    if (input.emailEnabled !== undefined) {
      updates.emailEnabled = input.emailEnabled;
    }
    if (input.emailFrequency !== undefined) {
      updates.emailFrequency = input.emailFrequency;
    }
    if (input.subscribedCategories !== undefined) {
      updates.subscribedCategories = input.subscribedCategories;
    }

    // Rebuild channels: start from existing, apply legacy email field changes, then channel overrides
    const newEmailEnabled = input.emailEnabled ?? existing.emailEnabled;
    const newSubscribedCategories = input.subscribedCategories ?? existing.subscribedCategories;
    const mergedChannels = { ...existing.channels };

    // Sync email legacy fields to channels.email
    mergedChannels.email = {
      enabled: newEmailEnabled,
      subscribedCategories: [...newSubscribedCategories],
    };

    // Apply explicit channel overrides
    if (input.channels) {
      for (const [ch, prefs] of Object.entries(input.channels) as [NotificationChannel, Partial<ChannelPreferences>][]) {
        if (ch === 'email') {
          // Email channel overrides also sync back to legacy fields
          if (prefs.enabled !== undefined) {
            mergedChannels.email!.enabled = prefs.enabled;
            updates.emailEnabled = prefs.enabled;
          }
          if (prefs.subscribedCategories !== undefined) {
            mergedChannels.email!.subscribedCategories = prefs.subscribedCategories;
            updates.subscribedCategories = prefs.subscribedCategories;
          }
        } else {
          const existing_ch = mergedChannels[ch];
          const defaultCh = ch in DEFAULT_CHANNEL_PREFERENCES
            ? DEFAULT_CHANNEL_PREFERENCES[ch as keyof typeof DEFAULT_CHANNEL_PREFERENCES]
            : { enabled: false, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };
          mergedChannels[ch] = {
            enabled: prefs.enabled ?? existing_ch?.enabled ?? defaultCh.enabled,
            subscribedCategories: prefs.subscribedCategories ?? existing_ch?.subscribedCategories ?? [...defaultCh.subscribedCategories],
          };
        }
      }
    }

    updates.channels = mergedChannels;

    const updated = this.repository.update(existing.id, updates);
    this.logger.info(`Updated preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user on a given channel.
   *
   * Returns true (allow delivery) when:
   * - No preferences record exists (default behavior per channel)
   * - The channel is enabled AND the category is in subscribedCategories
   *
   * For users with no preferences: email defaults to allowed, SMS/webhook to blocked.
   */
  shouldSendToChannel(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No preferences record → apply default channel behavior
    if (!prefs) {
      const defaultCh = channel in DEFAULT_CHANNEL_PREFERENCES
        ? DEFAULT_CHANNEL_PREFERENCES[channel as keyof typeof DEFAULT_CHANNEL_PREFERENCES]
        : undefined;
      if (!defaultCh) {
        return false;
      }
      return defaultCh.enabled && defaultCh.subscribedCategories.includes(notificationType);
    }

    const channelPrefs = prefs.channels?.[channel];
    if (!channelPrefs) {
      // Channel not configured — use defaults
      const defaultCh = channel in DEFAULT_CHANNEL_PREFERENCES
        ? DEFAULT_CHANNEL_PREFERENCES[channel as keyof typeof DEFAULT_CHANNEL_PREFERENCES]
        : undefined;
      if (!defaultCh) {
        return false;
      }
      return defaultCh.enabled && defaultCh.subscribedCategories.includes(notificationType);
    }

    if (!channelPrefs.enabled) {
      return false;
    }

    return channelPrefs.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether a notification of the given type should be delivered
   * to the given user via email. Backward-compatible wrapper.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSendToChannel(userId, 'email', notificationType);
  }

  /**
   * Get the email frequency setting for a user.
   * Returns 'immediate' if no preferences exist.
   */
  getEmailFrequency(userId: string): UserPreferences['emailFrequency'] {
    const prefs = this.repository.findByUserId(userId);
    return prefs?.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency;
  }

  /**
   * Subscribe a user to a notification category.
   */
  subscribeToCategory(userId: string, category: NotificationType): UserPreferences {
    const prefs = this.getOrCreateForUser(userId);

    if (prefs.subscribedCategories.includes(category)) {
      return prefs;
    }

    const newCategories = [...prefs.subscribedCategories, category];
    const updatedChannels = { ...prefs.channels };
    if (updatedChannels.email) {
      updatedChannels.email = { ...updatedChannels.email, subscribedCategories: newCategories };
    }

    return this.repository.update(prefs.id, {
      subscribedCategories: newCategories,
      channels: updatedChannels,
      updatedAt: new Date(),
    });
  }

  /**
   * Unsubscribe a user from a notification category.
   */
  unsubscribeFromCategory(userId: string, category: NotificationType): UserPreferences {
    const prefs = this.getOrCreateForUser(userId);

    if (!prefs.subscribedCategories.includes(category)) {
      return prefs;
    }

    const newCategories = prefs.subscribedCategories.filter((c) => c !== category);
    const updatedChannels = { ...prefs.channels };
    if (updatedChannels.email) {
      updatedChannels.email = { ...updatedChannels.email, subscribedCategories: newCategories };
    }

    return this.repository.update(prefs.id, {
      subscribedCategories: newCategories,
      channels: updatedChannels,
      updatedAt: new Date(),
    });
  }

  /**
   * Subscribe a user to a notification category on a specific channel.
   */
  subscribeToCategoryOnChannel(userId: string, channel: NotificationChannel, category: NotificationType): UserPreferences {
    const prefs = this.getOrCreateForUser(userId);
    const channelPrefs = prefs.channels?.[channel];

    if (channelPrefs?.subscribedCategories.includes(category)) {
      return prefs;
    }

    const updatedChannels = { ...prefs.channels };
    const defaultCh = channel in DEFAULT_CHANNEL_PREFERENCES
      ? DEFAULT_CHANNEL_PREFERENCES[channel as keyof typeof DEFAULT_CHANNEL_PREFERENCES]
      : { enabled: false, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };

    const current = updatedChannels[channel] ?? { ...defaultCh, subscribedCategories: [...defaultCh.subscribedCategories] };
    updatedChannels[channel] = {
      ...current,
      subscribedCategories: [...current.subscribedCategories, category],
    };

    const updates: Partial<UserPreferences> = { channels: updatedChannels, updatedAt: new Date() };

    // Keep email legacy fields in sync
    if (channel === 'email') {
      updates.subscribedCategories = updatedChannels.email!.subscribedCategories;
    }

    return this.repository.update(prefs.id, updates);
  }

  /**
   * Unsubscribe a user from a notification category on a specific channel.
   */
  unsubscribeFromCategoryOnChannel(userId: string, channel: NotificationChannel, category: NotificationType): UserPreferences {
    const prefs = this.getOrCreateForUser(userId);
    const channelPrefs = prefs.channels?.[channel];

    if (!channelPrefs?.subscribedCategories.includes(category)) {
      return prefs;
    }

    const updatedChannels = { ...prefs.channels };
    updatedChannels[channel] = {
      ...channelPrefs,
      subscribedCategories: channelPrefs.subscribedCategories.filter((c) => c !== category),
    };

    const updates: Partial<UserPreferences> = { channels: updatedChannels, updatedAt: new Date() };

    // Keep email legacy fields in sync
    if (channel === 'email') {
      updates.subscribedCategories = updatedChannels.email!.subscribedCategories;
    }

    return this.repository.update(prefs.id, updates);
  }

  /**
   * Enable or disable a specific channel for a user.
   */
  setChannelEnabled(userId: string, channel: NotificationChannel, enabled: boolean): UserPreferences {
    const prefs = this.getOrCreateForUser(userId);
    const updatedChannels = { ...prefs.channels };
    const defaultCh = channel in DEFAULT_CHANNEL_PREFERENCES
      ? DEFAULT_CHANNEL_PREFERENCES[channel as keyof typeof DEFAULT_CHANNEL_PREFERENCES]
      : { enabled: false, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };

    const current = updatedChannels[channel] ?? { ...defaultCh, subscribedCategories: [...defaultCh.subscribedCategories] };
    updatedChannels[channel] = { ...current, enabled };

    const updates: Partial<UserPreferences> = { channels: updatedChannels, updatedAt: new Date() };

    // Keep email legacy fields in sync
    if (channel === 'email') {
      updates.emailEnabled = enabled;
    }

    return this.repository.update(prefs.id, updates);
  }

  /**
   * Get all available notification categories.
   */
  getAvailableCategories(): NotificationType[] {
    return [...ALL_NOTIFICATION_CATEGORIES];
  }
}

/**
 * Build the channels map from input, merging defaults, legacy email fields, and explicit channel overrides.
 */
function buildChannelsFromInput(
  emailEnabled: boolean,
  subscribedCategories: NotificationType[],
  channelOverrides?: Partial<Record<NotificationChannel, Partial<ChannelPreferences>>>,
): Record<string, ChannelPreferences> {
  const channels: Record<string, ChannelPreferences> = {
    email: {
      enabled: emailEnabled,
      subscribedCategories: [...subscribedCategories],
    },
    sms: { ...DEFAULT_CHANNEL_PREFERENCES.sms, subscribedCategories: [...DEFAULT_CHANNEL_PREFERENCES.sms.subscribedCategories] },
    webhook: { ...DEFAULT_CHANNEL_PREFERENCES.webhook, subscribedCategories: [...DEFAULT_CHANNEL_PREFERENCES.webhook.subscribedCategories] },
  };

  if (channelOverrides) {
    for (const [ch, prefs] of Object.entries(channelOverrides) as [NotificationChannel, Partial<ChannelPreferences>][]) {
      const base = channels[ch] ?? { enabled: false, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };
      channels[ch] = {
        enabled: prefs.enabled ?? base.enabled,
        subscribedCategories: prefs.subscribedCategories ?? base.subscribedCategories,
      };
    }
  }

  return channels;
}

