describe('Multi-channel preferences', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('channels field in created preferences', () => {
    it('should include default channels when creating with defaults', () => {
      const prefs = service.createForUser('user-1');

      expect(prefs.channels.email).toEqual({
        enabled: true,
        subscribedCategories: [
          'order_confirmation',
          'order_status_update',
          'welcome',
          'account_updated',
        ],
      });
      expect(prefs.channels.sms).toEqual({
        enabled: false,
        subscribedCategories: [
          'order_confirmation',
          'order_status_update',
          'welcome',
          'account_updated',
        ],
      });
      expect(prefs.channels.webhook).toEqual({
        enabled: false,
        subscribedCategories: [
          'order_confirmation',
          'order_status_update',
          'welcome',
          'account_updated',
        ],
      });
    });

    it('should sync email legacy fields to channels.email', () => {
      const prefs = service.createForUser('user-1', {
        emailEnabled: false,
        subscribedCategories: ['welcome'],
      });

      expect(prefs.channels.email).toEqual({
        enabled: false,
        subscribedCategories: ['welcome'],
      });
      // Legacy fields still match
      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.subscribedCategories).toEqual(['welcome']);
    });

    it('should accept explicit channel overrides during creation', () => {
      const prefs = service.createForUser('user-1', {
        channels: {
          sms: { enabled: true, subscribedCategories: ['order_confirmation'] },
        },
      });

      expect(prefs.channels.sms).toEqual({
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });
      // Email still has defaults
      expect(prefs.channels.email?.enabled).toBe(true);
    });
  });

  describe('shouldSendToChannel', () => {
    it('should return true for email when no preferences exist (default opt-in)', () => {
      expect(service.shouldSendToChannel('user-1', 'email', 'order_confirmation')).toBe(true);
    });

    it('should return false for sms when no preferences exist (default opt-out)', () => {
      expect(service.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(false);
    });

    it('should return false for webhook when no preferences exist (default opt-out)', () => {
      expect(service.shouldSendToChannel('user-1', 'webhook', 'order_confirmation')).toBe(false);
    });

    it('should return true for sms when explicitly enabled', () => {
      service.createForUser('user-1', {
        channels: {
          sms: { enabled: true },
        },
      });

      expect(service.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(true);
    });

    it('should return false for sms when enabled but category not subscribed', () => {
      service.createForUser('user-1', {
        channels: {
          sms: { enabled: true, subscribedCategories: ['welcome'] },
        },
      });

      expect(service.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(false);
      expect(service.shouldSendToChannel('user-1', 'sms', 'welcome')).toBe(true);
    });

    it('should check email channel through channels map', () => {
      service.createForUser('user-1', { emailEnabled: false });

      expect(service.shouldSendToChannel('user-1', 'email', 'order_confirmation')).toBe(false);
    });

    it('should return false for in_app channel (no defaults configured)', () => {
      expect(service.shouldSendToChannel('user-1', 'in_app', 'order_confirmation')).toBe(false);
    });
  });

  describe('setChannelEnabled', () => {
    it('should enable sms channel', () => {
      service.createForUser('user-1');
      const updated = service.setChannelEnabled('user-1', 'sms', true);

      expect(updated.channels.sms?.enabled).toBe(true);
    });

    it('should disable email channel and sync legacy field', () => {
      service.createForUser('user-1');
      const updated = service.setChannelEnabled('user-1', 'email', false);

      expect(updated.channels.email?.enabled).toBe(false);
      expect(updated.emailEnabled).toBe(false);
    });

    it('should enable webhook channel', () => {
      service.createForUser('user-1');
      const updated = service.setChannelEnabled('user-1', 'webhook', true);

      expect(updated.channels.webhook?.enabled).toBe(true);
    });
  });

  describe('subscribeToCategoryOnChannel', () => {
    it('should add category to sms channel', () => {
      service.createForUser('user-1', {
        channels: { sms: { enabled: true, subscribedCategories: [] } },
      });

      const updated = service.subscribeToCategoryOnChannel('user-1', 'sms', 'welcome');

      expect(updated.channels.sms?.subscribedCategories).toContain('welcome');
    });

    it('should be idempotent', () => {
      service.createForUser('user-1', {
        channels: { sms: { enabled: true, subscribedCategories: ['welcome'] } },
      });

      const updated = service.subscribeToCategoryOnChannel('user-1', 'sms', 'welcome');

      expect(updated.channels.sms?.subscribedCategories.filter((c) => c === 'welcome')).toHaveLength(1);
    });

    it('should sync email legacy fields when subscribing on email channel', () => {
      service.createForUser('user-1', { subscribedCategories: [] });

      const updated = service.subscribeToCategoryOnChannel('user-1', 'email', 'welcome');

      expect(updated.subscribedCategories).toContain('welcome');
      expect(updated.channels.email?.subscribedCategories).toContain('welcome');
    });
  });

  describe('unsubscribeFromCategoryOnChannel', () => {
