      expect(updated.channels.sms?.subscribedCategories).not.toContain('order_confirmation');
    });

    it('should sync email legacy fields when unsubscribing on email channel', () => {
      service.createForUser('user-1');

      const updated = service.unsubscribeFromCategoryOnChannel('user-1', 'email', 'welcome');

      expect(updated.subscribedCategories).not.toContain('welcome');
      expect(updated.channels.email?.subscribedCategories).not.toContain('welcome');
    });
  });

  describe('updateForUser with channel overrides', () => {
    it('should update sms channel settings', () => {
      service.createForUser('user-1');
      const updated = service.updateForUser('user-1', {
        channels: {
          sms: { enabled: true, subscribedCategories: ['order_confirmation'] },
        },
      });

      expect(updated.channels.sms).toEqual({
        enabled: true,
        subscribedCategories: ['order_confirmation'],
      });
    });

    it('should update email via channels and sync legacy fields', () => {
      service.createForUser('user-1');
      const updated = service.updateForUser('user-1', {
        channels: {
          email: { enabled: false },
        },
      });

      expect(updated.channels.email?.enabled).toBe(false);
      expect(updated.emailEnabled).toBe(false);
    });

    it('should preserve other channels when updating one', () => {
      service.createForUser('user-1', {
        channels: { sms: { enabled: true } },
      });

      const updated = service.updateForUser('user-1', {
        channels: { webhook: { enabled: true } },
      });

      expect(updated.channels.sms?.enabled).toBe(true);
      expect(updated.channels.webhook?.enabled).toBe(true);
    });
  });
});

describe('NotificationService multi-channel preference enforcement', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let preferencesService: PreferencesService;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    smsAdapter = new SmsAdapter();
    webhookAdapter = new WebhookAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  const makeOrderCreatedEvent = (): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  it('should suppress sms notifications when sms channel is disabled (default)', async () => {
    // SMS is disabled by default — the event handler currently only dispatches to email,
    // but if it did dispatch to SMS, preferences would block it
    preferencesService.createForUser('user-1');

    expect(preferencesService.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(false);
    expect(preferencesService.shouldSendToChannel('user-1', 'email', 'order_confirmation')).toBe(true);
  });

  it('should allow sms notifications when sms channel is enabled', async () => {
    preferencesService.createForUser('user-1', {
      channels: { sms: { enabled: true } },
    });

    expect(preferencesService.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(true);
  });

  it('should enforce per-channel preferences independently', async () => {
    preferencesService.createForUser('user-1', {
      emailEnabled: false,
      channels: {
        sms: { enabled: true },
        webhook: { enabled: true, subscribedCategories: ['welcome'] },
      },
    });

    // Email disabled
    expect(preferencesService.shouldSendToChannel('user-1', 'email', 'order_confirmation')).toBe(false);
    // SMS enabled with all categories
    expect(preferencesService.shouldSendToChannel('user-1', 'sms', 'order_confirmation')).toBe(true);
    // Webhook enabled but only for welcome
    expect(preferencesService.shouldSendToChannel('user-1', 'webhook', 'order_confirmation')).toBe(false);
    expect(preferencesService.shouldSendToChannel('user-1', 'webhook', 'welcome')).toBe(true);
  });

  it('should still deliver email via EventBus when email preferences allow it', async () => {
    preferencesService.createForUser('user-1');

    await eventBus.emit(makeOrderCreatedEvent());

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress email via EventBus when email is disabled in channels', async () => {
    preferencesService.createForUser('user-1', { emailEnabled: false });

    await eventBus.emit(makeOrderCreatedEvent());

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });
});

