+/**
+ * Build the channels map from input, merging defaults, legacy email fields, and explicit channel overrides.
+ */
+function buildChannelsFromInput(
+  emailEnabled: boolean,
+  subscribedCategories: NotificationType[],
+  channelOverrides?: Partial<Record<NotificationChannel, Partial<ChannelPreferences>>>,
+): Record<string, ChannelPreferences> {
+  const channels: Record<string, ChannelPreferences> = {
+    email: {
+      enabled: emailEnabled,
+      subscribedCategories: [...subscribedCategories],
+    },
+    sms: { ...DEFAULT_CHANNEL_PREFERENCES.sms, subscribedCategories: [...DEFAULT_CHANNEL_PREFERENCES.sms.subscribedCategories] },
+    webhook: { ...DEFAULT_CHANNEL_PREFERENCES.webhook, subscribedCategories: [...DEFAULT_CHANNEL_PREFERENCES.webhook.subscribedCategories] },
+  };
+
+  if (channelOverrides) {
+    for (const [ch, prefs] of Object.entries(channelOverrides) as [NotificationChannel, Partial<ChannelPreferences>][]) {
+      const base = channels[ch] ?? { enabled: false, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };
+      channels[ch] = {
+        enabled: prefs.enabled ?? base.enabled,
+        subscribedCategories: prefs.subscribedCategories ?? base.subscribedCategories,
+      };
+    }
+  }
+
+  return channels;
+}

